28: public class GroupRebalanceConfig {
29: 
30:     public enum ProtocolType {
31:         CONSUMER,
32:         CONNECT,
33:         SHARE;
34: 
35:         @Override
36:         public String toString() {
37:             return super.toString().toLowerCase(Locale.ROOT);
38:         }
