44:     public final String groupId;
45:     public final Optional<String> groupInstanceId;
46:     public final Optional<String> rackId;
47:     public final long retryBackoffMs;
48:     public final long retryBackoffMaxMs;
49:     public final boolean leaveGroupOnClose;
50: 
51:     public GroupRebalanceConfig(AbstractConfig config, ProtocolType protocolType) {
52:         this.sessionTimeoutMs = config.getInt(CommonClientConfigs.SESSION_TIMEOUT_MS_CONFIG);
53: 
54:         // Consumer and Connect use different config names for defining rebalance timeout
55:         if ((protocolType == ProtocolType.CONSUMER) || (protocolType == ProtocolType.SHARE)) {
56:             this.rebalanceTimeoutMs = config.getInt(CommonClientConfigs.MAX_POLL_INTERVAL_MS_CONFIG);
57: 
58:             String rackId = config.getString(CommonClientConfigs.CLIENT_RACK_CONFIG);
59:             this.rackId = rackId == null || rackId.isEmpty() ? Optional.empty() : Optional.of(rackId);
60:         } else {
61:             this.rebalanceTimeoutMs = config.getInt(CommonClientConfigs.REBALANCE_TIMEOUT_MS_CONFIG);
62:             this.rackId = Optional.empty();
63:         }
64: 
65:         this.heartbeatIntervalMs = config.getInt(CommonClientConfigs.HEARTBEAT_INTERVAL_MS_CONFIG);
66:         this.groupId = config.getString(CommonClientConfigs.GROUP_ID_CONFIG);
67: 
68:         // Static membership is only introduced in consumer API.
69:         if (protocolType == ProtocolType.CONSUMER) {
70:             String groupInstanceId = config.getString(CommonClientConfigs.GROUP_INSTANCE_ID_CONFIG);
71:             if (groupInstanceId != null) {
72:                 JoinGroupRequest.validateGroupInstanceId(groupInstanceId);
73:                 this.groupInstanceId = Optional.of(groupInstanceId);
74:             } else {
75:                 this.groupInstanceId = Optional.empty();
76:             }
77:         } else {
78:             this.groupInstanceId = Optional.empty();
79:         }
80: 
81:         this.retryBackoffMs = config.getLong(CommonClientConfigs.RETRY_BACKOFF_MS_CONFIG);
82:         this.retryBackoffMaxMs = config.getLong(CommonClientConfigs.RETRY_BACKOFF_MAX_MS_CONFIG);
83: 
84:         // Internal leave group config is only defined in Consumer.
85:         if (protocolType == ProtocolType.CONSUMER) {
86:             this.leaveGroupOnClose = config.getBoolean("internal.leave.group.on.close");
87:         } else {
88:             this.leaveGroupOnClose = true;
89:         }
90:     }
91: 
92:     // For testing purpose.
93:     public GroupRebalanceConfig(final int sessionTimeoutMs,
94:                                 final int rebalanceTimeoutMs,
95:                                 final int heartbeatIntervalMs,
96:                                 String groupId,
97:                                 Optional<String> groupInstanceId,
98:                                 String rackId,
99:                                 long retryBackoffMs,
100:                                 long retryBackoffMaxMs,
101:                                 boolean leaveGroupOnClose) {
102:         this.sessionTimeoutMs = sessionTimeoutMs;
